using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;

namespace ResearchAgent;

/// <summary>
/// Provides web search and page-fetching capabilities for the research agent.
/// Uses DuckDuckGo HTML search (no API key required).
/// </summary>
public sealed partial class WebSearchTool : IDisposable
{
    private readonly HttpClient _httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
    };

    [Description("Searches the web for a query and returns result titles, snippets, and URLs. Returns up to 8 results.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(query);

        var encoded = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";

        var html = await _httpClient.GetStringAsync(url, cancellationToken);

        var results = ParseSearchResults(html);
        if (results.Count == 0)
            return $"No search results found for '{query}'.";

        var sb = new StringBuilder();
        sb.AppendLine($"Search results for: {query}");
        sb.AppendLine();

        foreach (var (title, snippet, resultUrl, i) in results.Select((r, i) => (r.Title, r.Snippet, r.Url, i)))
        {
            sb.AppendLine($"[{i + 1}] {title}");
            sb.AppendLine($"    URL: {resultUrl}");
            sb.AppendLine($"    {snippet}");
            sb.AppendLine();
        }

        return sb.ToString();
    }

    [Description("Fetches a web page and returns its text content (HTML tags stripped). Content is truncated to ~4000 characters.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL of the web page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(url);

        if (!Uri.TryCreate(url, UriKind.Absolute, out var uri)
            || (uri.Scheme != "http" && uri.Scheme != "https"))
        {
            return "Invalid URL. Please provide a full http:// or https:// URL.";
        }

        try
        {
            var html = await _httpClient.GetStringAsync(uri, cancellationToken);
            var text = ExtractText(html);

            const int maxLength = 4000;
            if (text.Length > maxLength)
                text = string.Concat(text.AsSpan(0, maxLength), "\n\n[Content truncated]");

            return string.IsNullOrWhiteSpace(text)
                ? "The page returned no readable text content."
                : text;
        }
        catch (HttpRequestException ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
        catch (TaskCanceledException)
        {
            return "Request timed out while fetching the page.";
        }
    }

    private static List<SearchResult> ParseSearchResults(string html)
    {
        var results = new List<SearchResult>();

        // DuckDuckGo HTML results use <a class="result__a" ...> for titles
        // and <a class="result__snippet" ...> for snippets
        var titleMatches = TitleRegex().Matches(html);
        var snippetMatches = SnippetRegex().Matches(html);

        var count = Math.Min(titleMatches.Count, 8);
        for (var i = 0; i < count; i++)
        {
            var titleMatch = titleMatches[i];
            var title = StripHtml(WebUtility.HtmlDecode(titleMatch.Groups[2].Value)).Trim();
            var href = WebUtility.HtmlDecode(titleMatch.Groups[1].Value).Trim();

            // Resolve DuckDuckGo redirect URLs
            if (href.StartsWith("//duckduckgo.com/l/?uddg=", StringComparison.Ordinal))
            {
                var uddgStart = href.IndexOf("uddg=", StringComparison.Ordinal) + 5;
                var uddgEnd = href.IndexOf('&', uddgStart);
                href = uddgEnd > 0
                    ? Uri.UnescapeDataString(href[uddgStart..uddgEnd])
                    : Uri.UnescapeDataString(href[uddgStart..]);
            }

            var snippet = i < snippetMatches.Count
                ? StripHtml(WebUtility.HtmlDecode(snippetMatches[i].Groups[1].Value)).Trim()
                : "";

            if (!string.IsNullOrWhiteSpace(title))
                results.Add(new SearchResult(title, snippet, href));
        }

        return results;
    }

    private static string ExtractText(string html)
    {
        // Remove script, style, and head sections
        var text = ScriptStyleRegex().Replace(html, " ");
        // Remove all HTML tags
        text = StripHtml(text);
        // Decode HTML entities
        text = WebUtility.HtmlDecode(text);
        // Collapse whitespace
        text = CollapseWhitespaceRegex().Replace(text, " ");
        text = CollapseNewlinesRegex().Replace(text, "\n\n");

        return text.Trim();
    }

    private static string StripHtml(string html) =>
        HtmlTagRegex().Replace(html, "");

    public void Dispose() => _httpClient.Dispose();

    private record SearchResult(string Title, string Snippet, string Url);

    [GeneratedRegex("""<a[^>]+class="result__a"[^>]*href="([^"]*)"[^>]*>(.*?)</a>""", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex TitleRegex();

    [GeneratedRegex("""<a[^>]+class="result__snippet"[^>]*>(.*?)</a>""", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("""<(script|style|head)[^>]*>.*?</\1>""", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStyleRegex();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex(@"[ \t]+")]
    private static partial Regex CollapseWhitespaceRegex();

    [GeneratedRegex(@"\n{3,}")]
    private static partial Regex CollapseNewlinesRegex();
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent;

/// <summary>
/// Provides in-memory note-taking capabilities for the research agent
/// to organize findings during a research session.
/// </summary>
public sealed class NoteTakingTool
{
