using System.ComponentModel;
using System.Text;

namespace ResearchAgent;

/// <summary>
/// Provides in-memory note-taking capabilities for the research agent
/// to organize findings during a research session.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];

    [Description("Saves a research note with a topic label and content. Use this to record key findings from web searches.")]
    public string AddNote(
        [Description("The topic or category label for this note (e.g., 'key findings', 'statistics', 'sources')")] string topic,
        [Description("The content of the note to save")] string content)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(topic);
        ArgumentException.ThrowIfNullOrWhiteSpace(content);

        _notes.Add(new ResearchNote(topic, content, DateTime.UtcNow));
        return $"Note #{_notes.Count} saved under topic '{topic}'.";
    }

    [Description("Retrieves all saved research notes, organized by topic. Use this before writing a final summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
        sb.AppendLine();

        var grouped = _notes.GroupBy(n => n.Topic, StringComparer.OrdinalIgnoreCase);
        foreach (var group in grouped)
        {
            sb.AppendLine($"--- {group.Key} ---");
            foreach (var note in group)
            {
                sb.AppendLine($"  • {note.Content}");
            }

            sb.AppendLine();
        }

        return sb.ToString();
    }

    private record ResearchNote(string Topic, string Content, DateTime Timestamp);
}

