using System.ClientModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent;

const string instructions = """
    You are a thorough research agent. When given a topic, you follow this process:

    1. SEARCH: Use SearchWebAsync to search for the topic. Run 2-3 searches with
       different query angles to get broad coverage.
    2. READ: Use FetchPageAsync to read the most relevant pages from search results
       (pick the top 2-3 most promising URLs).
    3. NOTE: Use AddNote to save key findings as you go. Organize notes by topic
       categories like "overview", "key facts", "statistics", "sources".
    4. REVIEW: Use GetAllNotes to review everything you've collected.
    5. SUMMARIZE: Write a well-structured summary of your research findings,
       citing the sources you used.

    Be factual and cite your sources. If search results are limited, note that
    in your summary.
    """;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build tools ---
using var webSearch = new WebSearchTool();
var noteTaking = new NoteTakingTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(noteTaking.AddNote),
    AIFunctionFactory.Create(noteTaking.GetAllNotes),
};

// --- Build the chat client ---
IChatClient chatClient = new ChatClientBuilder(
        new OpenAIClient(new ApiKeyCredential(apiKey))
            .GetChatClient(modelId)
            .AsIChatClient())
    .Build();

// --- Build the agent ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "Researches topics using web search and note-taking",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = tools,
        },
    });

// --- Run ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine("This may take a minute while the agent searches and reads pages...");
Console.WriteLine();

var session = await agent.CreateSessionAsync();

var response = await agent.RunAsync(
    $"Please research the following topic and provide a comprehensive summary: {topic}",
    session);

Console.WriteLine("═══════════════ Results ═══════════════");
Console.WriteLine();
Console.WriteLine(response.Text);
Console.WriteLine();
Console.WriteLine("═══════════════════════════════════════");

if (response.Usage is { } usage)
{
    Console.WriteLine($"Tokens — Input: {usage.InputTokenCount}, Output: {usage.OutputTokenCount}, "
                    + $"Total: {usage.TotalTokenCount}");
}

